import{_ as n,C as d,c as l,o,a2 as t,b as r,w as a,a as c,G as i,a3 as p}from"./chunks/framework.CriqKoQt.js";const b=JSON.parse('{"title":"DCloud 插件市场验证码自动识别脚本","description":"","frontmatter":{},"headers":[],"relativePath":"scripts/tamper-monkey/dcloud-plugin/article.md","filePath":"scripts/tamper-monkey/dcloud-plugin/article.md","lastUpdated":1775551557000}'),u={name:"scripts/tamper-monkey/dcloud-plugin/article.md"};function h(g,e,E,A,v,C){const s=d("Mermaid");return o(),l("div",null,[e[1]||(e[1]=t(`<h1 id="dcloud-插件市场验证码自动识别脚本" tabindex="-1">DCloud 插件市场验证码自动识别脚本 <a class="header-anchor" href="#dcloud-插件市场验证码自动识别脚本" aria-label="Permalink to &quot;DCloud 插件市场验证码自动识别脚本&quot;">​</a></h1><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>一个油猴（Tampermonkey）用户脚本，配合本地 OCR 服务，实现 DCloud 插件市场（<code>ext.dcloud.net.cn</code>）验证码的<strong>全自动识别、填入、提交和错误重试</strong>。用户只需手动点击一次&quot;下载插件并导入HBuilderX&quot;，后续的验证码流程全部自动完成。</p><h3 id="核心架构" tabindex="-1">核心架构 <a class="header-anchor" href="#核心架构" aria-label="Permalink to &quot;核心架构&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>油猴脚本（前端）  ←→  本地 OCR 服务（localhost:18099）</span></span>
<span class="line"><span>     ↓                        ↓</span></span>
<span class="line"><span>MutationObserver          ddddocr 识别引擎</span></span>
<span class="line"><span>监听 DOM 变化              图片 → 4位小写字母</span></span></code></pre></div><h3 id="自动化流程" tabindex="-1">自动化流程 <a class="header-anchor" href="#自动化流程" aria-label="Permalink to &quot;自动化流程&quot;">​</a></h3>`,6)),(o(),r(p,null,{default:a(()=>[i(s,{id:"mermaid-16",class:"mermaid my-mermaid-class",graph:"flowchart%20TD%0A%20%20%20%20A%5B%E7%94%A8%E6%88%B7%E6%89%8B%E5%8A%A8%E7%82%B9%E5%87%BB%3Cbr%2F%3E%E2%80%9C%E4%B8%8B%E8%BD%BD%E6%8F%92%E4%BB%B6%E5%B9%B6%E5%AF%BC%E5%85%A5HBuilderX%E2%80%9D%5D%20--%3E%20B%5B%E8%84%9A%E6%9C%AC%E8%AE%B0%E5%BD%95%E7%94%A8%E6%88%B7%E8%A1%8C%E4%B8%BA%5D%0A%20%20%20%20B%20--%3E%20C%5B%E9%AA%8C%E8%AF%81%E7%A0%81%E5%BC%B9%E7%AA%97%E5%87%BA%E7%8E%B0%5D%0A%20%20%20%20C%20--%3E%20D%5B%E5%9B%BE%E7%89%87%E8%BD%AC%20Base64%5D%0A%20%20%20%20D%20--%3E%20E%5B%E8%B0%83%E7%94%A8%E6%9C%AC%E5%9C%B0%20OCR%20%E6%9C%8D%E5%8A%A1%5D%0A%20%20%20%20E%20--%3E%20F%7B%22%E8%AF%86%E5%88%AB%E7%BB%93%E6%9E%9C%E6%9C%89%E6%95%88%3F%3Cbr%2F%3E4%E4%BD%8D%E5%B0%8F%E5%86%99%E5%AD%97%E6%AF%8D%22%7D%0A%20%20%20%20F%20--%3E%7C%E2%9C%85%20%E6%9C%89%E6%95%88%7C%20G%5B%E8%87%AA%E5%8A%A8%E5%A1%AB%E5%85%A5%E8%BE%93%E5%85%A5%E6%A1%86%5D%0A%20%20%20%20G%20--%3E%20H%5B%E8%87%AA%E5%8A%A8%E7%82%B9%E5%87%BB%E2%80%9C%E6%8F%90%E4%BA%A4%E2%80%9D%5D%0A%20%20%20%20H%20--%3E%20I%7B%E6%8F%90%E4%BA%A4%E7%BB%93%E6%9E%9C%7D%0A%20%20%20%20I%20--%3E%7C%E6%88%90%E5%8A%9F%20-%20%E5%BC%B9%E7%AA%97%E6%B6%88%E5%A4%B1%7C%20J%5B%E9%87%8A%E6%94%BE%E9%94%81%20%2B%20%E8%87%AA%E5%8A%A8%E7%BB%AD%E7%82%B9%E4%B8%8B%E8%BD%BD%5D%0A%20%20%20%20J%20--%3E%20C%0A%20%20%20%20I%20--%3E%7C%E5%A4%B1%E8%B4%A5%20-%20%E9%94%99%E8%AF%AF%E5%BC%B9%E7%AA%97%7C%20K%5B%E8%87%AA%E5%8A%A8%E7%82%B9%E5%87%BB%E2%80%9C%E7%A1%AE%E8%AE%A4%E2%80%9D%5D%0A%20%20%20%20K%20--%3E%20L%5B%E8%87%AA%E5%8A%A8%E6%8D%A2%E5%9B%BE%E9%87%8D%E8%AF%95%5D%0A%20%20%20%20L%20--%3E%20D%0A%20%20%20%20F%20--%3E%7C%E2%9D%8C%20%E6%97%A0%E6%95%88%7C%20M%7B%E9%87%8D%E8%AF%95%20%3C%208%E6%AC%A1%3F%7D%0A%20%20%20%20M%20--%3E%7C%E6%98%AF%7C%20N%5B%E8%87%AA%E5%8A%A8%E6%8D%A2%E5%9B%BE%5D%0A%20%20%20%20N%20--%3E%20D%0A%20%20%20%20M%20--%3E%7C%E5%90%A6%7C%20O%5B%22%E5%81%9C%E6%AD%A2%E8%87%AA%E5%8A%A8%E6%8F%90%E4%BA%A4%3Cbr%2F%3E%E5%A1%AB%E5%85%A5%E7%BB%93%E6%9E%9C%E4%BE%9B%E6%89%8B%E5%8A%A8%E6%A0%B8%E5%AE%9E%22%5D%0A"})]),fallback:a(()=>e[0]||(e[0]=[c(" Loading... ")])),_:1})),e[2]||(e[2]=t(`<hr><h2 id="迭代历程" tabindex="-1">迭代历程 <a class="header-anchor" href="#迭代历程" aria-label="Permalink to &quot;迭代历程&quot;">​</a></h2><h3 id="v2-0-—-基础版本" tabindex="-1">v2.0 — 基础版本 <a class="header-anchor" href="#v2-0-—-基础版本" aria-label="Permalink to &quot;v2.0 — 基础版本&quot;">​</a></h3><p><strong>起点</strong>：已有一个能自动识别验证码并填入输入框的脚本，具备：</p><ul><li>验证码图片转 Base64（canvas / fetch 两种方式）</li><li>调用本地 OCR 服务识别（<code>GM_xmlhttpRequest</code> 跨域请求）</li><li>识别结果格式校验（<code>/^[a-z]{4}$/</code>）</li><li>格式无效时自动换图重试（最多 5 次）</li><li>Base64 面板展示 + 复制功能</li></ul><h3 id="v3-0-—-自动点击下载-自动提交-拦截弹窗" tabindex="-1">v3.0 — 自动点击下载 + 自动提交 + 拦截弹窗 <a class="header-anchor" href="#v3-0-—-自动点击下载-自动提交-拦截弹窗" aria-label="Permalink to &quot;v3.0 — 自动点击下载 + 自动提交 + 拦截弹窗&quot;">​</a></h3><p><strong>用户需求</strong>：OCR 识别填入后，自动点击&quot;提交&quot;按钮；页面加载时自动点击&quot;下载插件并导入HBuilderX&quot;；拦截浏览器的 <code>hbuilderx://</code> 协议弹窗。</p><p><strong>新增</strong>：</p><ul><li><code>autoClickDownloadBtn()</code> — 页面加载后自动点击下载按钮</li><li><code>autoClickSubmitBtn()</code> — 识别成功后延迟 600ms 自动提交</li><li><code>interceptProtocolDialog()</code> — 覆盖 <code>document.createElement</code> 拦截 iframe 协议跳转</li></ul><h3 id="v3-1-—-移除协议拦截" tabindex="-1">v3.1 — 移除协议拦截 <a class="header-anchor" href="#v3-1-—-移除协议拦截" aria-label="Permalink to &quot;v3.1 — 移除协议拦截&quot;">​</a></h3><p><strong>问题</strong>：覆盖 <code>document.createElement</code> 导致页面报 <code>TypeError: Cannot read properties of undefined (reading &#39;click&#39;)</code>，且浏览器原生协议弹窗（&quot;要打开 HBuilderX 吗？&quot;）JS 无法控制。</p><p><strong>修复</strong>：删除整个 <code>interceptProtocolDialog()</code> 函数，协议弹窗由用户手动处理。</p><h3 id="v3-2-—-错误弹窗自动处理" tabindex="-1">v3.2 — 错误弹窗自动处理 <a class="header-anchor" href="#v3-2-—-错误弹窗自动处理" aria-label="Permalink to &quot;v3.2 — 错误弹窗自动处理&quot;">​</a></h3><p><strong>用户需求</strong>：验证码错误时会弹出 Bootstrap 模态框（&quot;请输入验证码!&quot;），希望自动点击&quot;确认&quot;并重试。</p><p><strong>新增</strong>：</p><ul><li><code>observeErrorDialog()</code> — MutationObserver 监听 <code>.modal-dialog</code> 出现</li><li>检测弹窗内容包含&quot;验证码/请输入/错误&quot;等关键词</li><li>自动点击确认按钮 → 自动换图 → 重新 OCR（最多 5 次）</li></ul><h3 id="v3-3-—-🔥-修复死循环" tabindex="-1">v3.3 — 🔥 修复死循环 <a class="header-anchor" href="#v3-3-—-🔥-修复死循环" aria-label="Permalink to &quot;v3.3 — 🔥 修复死循环&quot;">​</a></h3><p><strong>问题</strong>：两个独立的重试计数器（OCR 格式校验 5 次 + 错误弹窗 5 次）互不影响，形成 <strong>5+5+5+5+...</strong> 的无限循环。</p><p><strong>根因分析</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>OCR 识别无效 → 换图重试 5 次 → 耗尽后填入无效结果并提交</span></span>
<span class="line"><span>→ 错误弹窗 → 确认 → 换图重试 5 次 → 又填入并提交</span></span>
<span class="line"><span>→ 又弹错误弹窗 → ... 无限循环</span></span></code></pre></div><p><strong>修复</strong>：</p><ul><li>统一为<strong>一个全局重试计数器</strong> <code>retryCount</code>，上限 <code>MAX_TOTAL_RETRY = 8</code></li><li>OCR 重试耗尽后<strong>只填入不提交</strong>，切断循环链</li><li>添加 <code>isProcessing</code> 全局处理锁，防止并发触发</li></ul><h3 id="v3-4-—-移除自动下载" tabindex="-1">v3.4 — 移除自动下载 <a class="header-anchor" href="#v3-4-—-移除自动下载" aria-label="Permalink to &quot;v3.4 — 移除自动下载&quot;">​</a></h3><p><strong>用户需求</strong>：不希望页面加载时自动点击下载按钮，改为手动触发。</p><p><strong>修复</strong>：删除 <code>autoClickDownloadBtn()</code>、<code>observeDownloadBtn()</code> 及相关变量。</p><h3 id="v3-4-1-—-修复语法错误" tabindex="-1">v3.4.1 — 修复语法错误 <a class="header-anchor" href="#v3-4-1-—-修复语法错误" aria-label="Permalink to &quot;v3.4.1 — 修复语法错误&quot;">​</a></h3><p><strong>问题</strong>：删除代码时两段注释被错误合并，<code>function observeErrorDialog()</code> 被吞进注释，导致 <code>SyntaxError</code>。</p><p><strong>修复</strong>：恢复正确的函数声明。</p><h3 id="v3-5-—-🔥-修复竞态条件" tabindex="-1">v3.5 — 🔥 修复竞态条件 <a class="header-anchor" href="#v3-5-—-🔥-修复竞态条件" aria-label="Permalink to &quot;v3.5 — 🔥 修复竞态条件&quot;">​</a></h3><p><strong>问题</strong>：OCR 识别正确并填入后，在等待提交的 600ms 内（或提交后），验证码图片 <code>src</code> 可能变化，MutationObserver 触发新一轮 OCR，<strong>覆盖了已正确填入的验证码</strong>，导致永远提交错误。</p><p><strong>修复</strong>：</p><ul><li>新增 <code>isSubmitting</code> 提交等待锁 — 填入成功后立即上锁，阻止新的 OCR 处理</li><li>MutationObserver 检测到 <code>src</code> 变化时，若 <code>isSubmitting</code> 为 true 则忽略</li><li><code>src</code> 变化增加 600ms 防抖</li><li>锁释放时机：错误弹窗出现 / 5 秒超时 / 手动换图</li></ul><h3 id="v3-6-—-弹窗消失检测" tabindex="-1">v3.6 — 弹窗消失检测 <a class="header-anchor" href="#v3-6-—-弹窗消失检测" aria-label="Permalink to &quot;v3.6 — 弹窗消失检测&quot;">​</a></h3><p><strong>问题</strong>：验证码正确提交成功后，弹窗直接消失（不弹错误弹窗），<code>isSubmitting</code> 锁只能等 5 秒超时释放，导致短时间内再次操作时 OCR 不触发。</p><p><strong>修复</strong>：在 <code>observeErrorDialog</code> 中增加 <code>removedNodes</code> 监听，检测包含验证码元素的 DOM 被移除时立即释放所有锁。</p><h3 id="v3-7-—-用户触发后自动续点下载" tabindex="-1">v3.7 — 用户触发后自动续点下载 <a class="header-anchor" href="#v3-7-—-用户触发后自动续点下载" aria-label="Permalink to &quot;v3.7 — 用户触发后自动续点下载&quot;">​</a></h3><p><strong>用户需求</strong>：希望加回自动点击下载按钮的功能，但改为<strong>跟随用户行为</strong>：用户手动点击过一次后，后续自动持续点击；未点击过则不主动触发。</p><p><strong>新增</strong>：</p><ul><li><code>userClickedDownload</code> 标记 — 记录用户是否手动点击过下载按钮</li><li><code>observeDownloadBtn()</code> — 事件委托监听用户点击下载按钮</li><li><code>autoClickDownloadBtn()</code> — 查找并点击下载按钮</li><li>提交成功（弹窗消失）后，若用户曾点击过，延迟 1.5 秒自动续点</li></ul><h3 id="v3-8-—-🔥-修复自动换图导致卡住" tabindex="-1">v3.8 — 🔥 修复自动换图导致卡住 <a class="header-anchor" href="#v3-8-—-🔥-修复自动换图导致卡住" aria-label="Permalink to &quot;v3.8 — 🔥 修复自动换图导致卡住&quot;">​</a></h3><p><strong>问题</strong>：脚本自动调用 <code>clickRefreshCaptcha()</code> 换图时，<code>.click()</code> 产生的事件冒泡会触发 <code>observeRefreshButton</code> 中的监听器，导致两个严重问题：</p><ol><li><strong>重试计数器被误重置</strong>：<code>observeRefreshButton</code> 无条件执行 <code>retryCount = 0</code>，导致自动重试永远无法达到 <code>MAX_TOTAL_RETRY</code> 上限，OCR 持续返回无效结果时会无限重试</li><li><strong>双重触发竞态</strong>：<code>observeRefreshButton</code>（800ms 延迟）和 MutationObserver 的 <code>src</code> 变化防抖（600ms）同时触发 <code>processCaptchaImg</code>，两者竞争导致 <code>isProcessing</code> 锁或 <code>b64Processed</code> 标记状态混乱，表现为脚本&quot;卡住&quot;不动</li></ol><p><strong>根因分析</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>脚本自动换图 clickRefreshCaptcha()</span></span>
<span class="line"><span>  → .click() 事件冒泡到 document</span></span>
<span class="line"><span>  → observeRefreshButton 监听到 → retryCount = 0（误重置！）+ 800ms 后触发处理</span></span>
<span class="line"><span>  → 同时 MutationObserver 监听到 src 变化 → 600ms 防抖后触发处理</span></span>
<span class="line"><span>  → 两个处理竞争 → 状态混乱 → 卡住</span></span></code></pre></div><p><strong>修复</strong>：</p><ul><li>新增 <code>isAutoRefreshing</code> 标记 — 脚本自动换图前设为 <code>true</code>，事件冒泡完成后重置</li><li><code>observeRefreshButton</code> 检测到 <code>isAutoRefreshing</code> 为 <code>true</code> 时跳过处理，不重置计数器也不重复触发</li><li>只有<strong>用户手动点击</strong>换图时才重置所有状态</li></ul><h3 id="v3-9-—-🔥-修复连续下载时不再自动续点" tabindex="-1">v3.9 — 🔥 修复连续下载时不再自动续点 <a class="header-anchor" href="#v3-9-—-🔥-修复连续下载时不再自动续点" aria-label="Permalink to &quot;v3.9 — 🔥 修复连续下载时不再自动续点&quot;">​</a></h3><p><strong>问题</strong>：第一次验证码提交成功后能正常自动续点&quot;下载插件并导入HBuilderX&quot;，但第二次及以后不再自动续点。</p><p><strong>根因分析</strong>：</p><p>DCloud 使用 Bootstrap 模态框，弹窗关闭时有两种方式：</p><ol><li><strong>移除 DOM 节点</strong>（<code>removedNodes</code> 可检测）</li><li><strong>CSS 隐藏</strong>（<code>display: none</code> 或移除 <code>in</code> class）</li></ol><p>之前的代码只通过 <code>MutationObserver</code> 的 <code>removedNodes</code> 检测弹窗消失。第一次提交成功时 DOM 被移除，检测正常；但后续提交成功时，Bootstrap 可能<strong>复用已有 DOM 并通过 CSS 隐藏</strong>，<code>removedNodes</code> 不会触发，导致 <code>handleSubmitSuccess</code> 永远不被调用。</p><p><strong>修复</strong>：</p><ul><li>提取公共函数 <code>handleSubmitSuccess()</code> — 统一处理提交成功后的状态重置和自动续点</li><li>新增 <code>startSubmitSuccessPolling()</code> — 提交后启动轮询（每 500ms），检查验证码弹窗是否仍可见（通过 <code>offsetParent</code> 和 <code>.modal.in</code> 判断）</li><li>保留原有的 <code>removedNodes</code> 检测作为快速路径，轮询作为兜底</li><li>两种检测方式互不冲突：先触发的执行 <code>handleSubmitSuccess()</code>，后触发的因 <code>isSubmitting</code> 已为 <code>false</code> 而跳过</li></ul><h3 id="v3-10-—-🔥-修复-ocr-返回空字符串导致卡住" tabindex="-1">v3.10 — 🔥 修复 OCR 返回空字符串导致卡住 <a class="header-anchor" href="#v3-10-—-🔥-修复-ocr-返回空字符串导致卡住" aria-label="Permalink to &quot;v3.10 — 🔥 修复 OCR 返回空字符串导致卡住&quot;">​</a></h3><p><strong>问题</strong>：OCR 服务偶尔返回空字符串 <code>&quot;&quot;</code>，脚本卡住不动，不会自动换图重试。</p><p><strong>根因分析</strong>：</p><p>两个缺陷叠加导致卡死：</p><ol><li><strong><code>recognizeCaptcha</code> 误判空字符串为失败</strong>：判断条件 <code>data.code === 0 &amp;&amp; data.result</code> 中，空字符串 <code>&quot;&quot;</code> 是 falsy 值，导致走进 <code>reject</code> 分支抛出&quot;识别失败&quot;错误</li><li><strong><code>processCaptchaImg</code> 的 catch 分支没有重试逻辑</strong>：OCR 异常被 catch 后只显示错误信息，没有触发自动换图重试，脚本就此停止</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>OCR 返回 { code: 0, result: &quot;&quot; }</span></span>
<span class="line"><span>  → data.result 为 &quot;&quot; (falsy) → 条件 data.code === 0 &amp;&amp; data.result 为 false</span></span>
<span class="line"><span>  → reject(&quot;识别失败&quot;) → 进入 catch 分支</span></span>
<span class="line"><span>  → 只显示错误面板，不换图不重试 → 卡住</span></span></code></pre></div><p><strong>修复</strong>：</p><ul><li><code>recognizeCaptcha</code> 中将 <code>data.result</code> 的判断改为 <code>typeof data.result === &#39;string&#39;</code>，允许空字符串通过，交给后续格式校验处理</li><li><code>processCaptchaImg</code> 的 catch 分支增加自动换图重试逻辑（共享全局重试计数器），OCR 服务异常时也能自动恢复</li></ul><h3 id="v4-0-—-🐕-watchdog-看门狗机制-彻底解决卡住问题" tabindex="-1">v4.0 — 🐕 Watchdog 看门狗机制（彻底解决卡住问题） <a class="header-anchor" href="#v4-0-—-🐕-watchdog-看门狗机制-彻底解决卡住问题" aria-label="Permalink to &quot;v4.0 — 🐕 Watchdog 看门狗机制（彻底解决卡住问题）&quot;">​</a></h3><p><strong>问题</strong>：之前的方案是&quot;逐个修复卡住的边界情况&quot;，但总有新的边界情况出现（空字符串、DOM 异常、竞态条件……），修不完。</p><p><strong>新思路</strong>：不再试图修复每一种卡住的情况，而是从&quot;结果&quot;出发——如果一段时间内没有任何有效活动，就判定卡住了，自动恢复。</p><p><strong>核心机制</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户首次点击&quot;下载插件并导入HBuilderX&quot;</span></span>
<span class="line"><span>  → 启动 Watchdog（每 3 秒检查一次）</span></span>
<span class="line"><span>  → 每次有效活动（OCR 请求/响应、提交、换图、成功）时更新 lastActivityTime</span></span>
<span class="line"><span>  → 如果超过 15 秒无活动 → 判定卡住</span></span>
<span class="line"><span>    → 验证码弹窗还在？→ 重置状态 + 换图重试</span></span>
<span class="line"><span>    → 弹窗不在？→ 重新点击下载按钮</span></span>
<span class="line"><span>    → 下载按钮也找不到？→ 3 秒后刷新整个页面</span></span></code></pre></div><p><strong>关键改动</strong>：</p><ol><li>新增 <code>tickActivity(reason)</code> — 在每个关键操作处调用，更新活动时间戳并打印心跳日志</li><li>新增 <code>startWatchdog()</code> / <code>stopWatchdog()</code> — 用户首次点击下载后启动，定期检查活动超时</li><li>新增 <code>resetAllState()</code> — 统一重置所有状态（看门狗触发时 / 提交成功时共用）</li><li><strong>去掉&quot;达到重试上限就停止&quot;的逻辑</strong> — 达到 <code>MAX_TOTAL_RETRY</code> 后重置计数器继续重试，永不停止</li><li>错误弹窗后的重试也不再有上限，由看门狗兜底防止无限循环</li></ol><p><strong>活动心跳点</strong>：</p><ul><li>OCR 请求发出 / 响应返回</li><li>验证码提交</li><li>无效结果换图重试</li><li>OCR 失败换图重试</li><li>错误弹窗换图重试</li><li>提交成功</li><li>自动续点下载</li><li>用户点击下载按钮</li><li>看门狗恢复操作</li></ul><hr><h2 id="关键技术点" tabindex="-1">关键技术点 <a class="header-anchor" href="#关键技术点" aria-label="Permalink to &quot;关键技术点&quot;">​</a></h2><table tabindex="0"><thead><tr><th>技术</th><th>用途</th></tr></thead><tbody><tr><td><code>MutationObserver</code></td><td>监听验证码弹窗出现/消失、图片 src 变化、错误弹窗</td></tr><tr><td><code>GM_xmlhttpRequest</code></td><td>跨域调用本地 OCR 服务</td></tr><tr><td>Canvas / Fetch</td><td>图片转 Base64</td></tr><tr><td>原生 <code>HTMLInputElement.prototype.value</code> setter</td><td>绕过框架限制填入输入框</td></tr><tr><td>全局状态锁（<code>isProcessing</code> / <code>isSubmitting</code>）</td><td>防止竞态条件和并发冲突</td></tr><tr><td>统一重试计数器</td><td>防止死循环</td></tr><tr><td>防抖（<code>srcChangeTimer</code>）</td><td>避免 src 频繁变化重复触发</td></tr><tr><td>用户行为跟踪（<code>userClickedDownload</code>）</td><td>智能续点下载</td></tr><tr><td>自动换图标记（<code>isAutoRefreshing</code>）</td><td>区分脚本自动换图与用户手动换图，防止竞态</td></tr><tr><td>提交成功轮询（<code>submitSuccessTimer</code>）</td><td>兼容 DOM 移除和 CSS 隐藏两种弹窗关闭方式</td></tr><tr><td>OCR 失败自动重试</td><td>catch 分支也触发换图重试，防止 OCR 异常导致卡死</td></tr><tr><td><strong>Watchdog 看门狗</strong></td><td><strong>全局超时检测，无论什么原因卡住都能自动恢复</strong></td></tr><tr><td><strong>二级看门狗 + 页面刷新</strong></td><td><strong>检测浏览器系统弹窗卡住的情况，自动刷新页面恢复</strong></td></tr></tbody></table><h3 id="v4-1-—-🐕-看门狗增强-系统弹窗检测-自动刷新页面" tabindex="-1">v4.1 — 🐕 看门狗增强：系统弹窗检测 + 自动刷新页面 <a class="header-anchor" href="#v4-1-—-🐕-看门狗增强-系统弹窗检测-自动刷新页面" aria-label="Permalink to &quot;v4.1 — 🐕 看门狗增强：系统弹窗检测 + 自动刷新页面&quot;">​</a></h3><p><strong>问题</strong>：验证码提交成功后，浏览器会弹出系统级确认弹窗（&quot;要打开 HBuilderX 吗？&quot;），这是浏览器原生的 protocol handler 弹窗，<strong>JavaScript 无法检测也无法关闭</strong>。v4.0 的看门狗在这种情况下只会反复点击下载按钮，但系统弹窗挡住了，点击无效，脚本仍然卡住。</p><p><strong>解决方案</strong>：三级恢复策略</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>看门狗触发（15秒无活动）</span></span>
<span class="line"><span>  ├─ 验证码弹窗还在？→ 换图重新识别</span></span>
<span class="line"><span>  ├─ 没有验证码弹窗？→ 点击下载按钮</span></span>
<span class="line"><span>  │   └─ 启动二级超时（10秒）</span></span>
<span class="line"><span>  │       ├─ 10秒内出现验证码弹窗 → 正常恢复 ✅</span></span>
<span class="line"><span>  │       └─ 10秒内仍无弹窗 → 被系统弹窗卡住 → 刷新页面 🔄</span></span>
<span class="line"><span>  └─ 下载按钮也找不到？→ 直接刷新页面 🔄</span></span>
<span class="line"><span></span></span>
<span class="line"><span>连续触发 &gt; 2 次？→ 直接刷新页面（不再尝试恢复）🔄</span></span></code></pre></div><p><strong>关键改动</strong>：</p><ol><li>新增 <code>WATCHDOG_RECOVERY_TIMEOUT</code>（10秒）— 点击下载按钮后的二级超时，检测是否被系统弹窗卡住</li><li>新增 <code>WATCHDOG_MAX_CONSECUTIVE</code>（2次）— 连续触发上限，超过直接刷新页面</li><li>新增 <code>startRecoveryTimeout()</code> / <code>stopRecoveryTimeout()</code> — 二级超时管理</li><li>新增 <code>watchdogConsecutiveCount</code> — 连续触发计数器，有正常活动时自动重置</li><li><code>resetAllState()</code> 中增加清理二级超时定时器</li></ol>`,80))])}const m=n(u,[["render",h]]);export{b as __pageData,m as default};
